contracts/PointsSystem.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract PointsSystem {
    mapping(address => uint256) public points;
    mapping(address => uint256) public totalEarned;

    // Daily earning caps
    mapping(address => uint256) public lastEarnDay;
    mapping(address => uint256) public dailyEarned;
    uint256 public constant MAX_DAILY_EARN = 500;

    address public owner;
    mapping(address => bool) public authorisedCallers; // PostRegistry gets authorised

    event PointsAwarded(address indexed user, uint256 amount, string reason, uint256 newBalance);
    event PointsSpent(address indexed user, uint256 amount, string reason, uint256 newBalance);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    modifier onlyAuthorised() {
        require(authorisedCallers[msg.sender] || msg.sender == owner, "Not authorised");
        _;
    }

    constructor() {
        owner = msg.sender;
        authorisedCallers[msg.sender] = true;
    }

    function authoriseCaller(address caller) external onlyOwner {
        authorisedCallers[caller] = true;
    }

    function awardPoints(address user, uint256 amount, string calldata reason) external onlyAuthorised {
        // Daily cap check
        uint256 today = block.timestamp / 86400;
        if (lastEarnDay[user] != today) {
            lastEarnDay[user] = today;
            dailyEarned[user] = 0;
        }

        uint256 remaining = MAX_DAILY_EARN > dailyEarned[user] ? MAX_DAILY_EARN - dailyEarned[user] : 0;
        uint256 actualAmount = amount > remaining ? remaining : amount;

        if (actualAmount > 0) {
            points[user] += actualAmount;
            totalEarned[user] += actualAmount;
            dailyEarned[user] += actualAmount;
            emit PointsAwarded(user, actualAmount, reason, points[user]);
        }
    }

    function spendPoints(address user, uint256 amount, string calldata reason) external onlyAuthorised {
        require(points[user] >= amount, "Insufficient points");
        points[user] -= amount;
        emit PointsSpent(user, amount, reason, points[user]);
    }

    // Welcome bonus for new users
    function claimWelcomeBonus() external {
        require(totalEarned[msg.sender] == 0, "Already claimed");
        points[msg.sender] += 225;
        totalEarned[msg.sender] += 225;
        emit PointsAwarded(msg.sender, 225, "welcome_bonus", points[msg.sender]);
    }

    function getPoints(address user) external view returns (uint256) {
        return points[user];
    }

    function getDailyEarned(address user) external view returns (uint256) {
        uint256 today = block.timestamp / 86400;
        if (lastEarnDay[user] != today) return 0;
        return dailyEarned[user];
    }
}

contracts/PostRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IPointsSystem {
    function awardPoints(address user, uint256 amount, string calldata reason) external;
}

contract PostRegistry {
    struct Post {
        uint256 id;
        address author;
        string arweaveId;        // content stored on Arweave
        string contentType;      // "text" or "image"
        uint256 createdAt;
        uint256 likes;
        bool exists;
    }

    IPointsSystem public pointsSystem;
    address public owner;

    uint256 public totalPosts;
    mapping(uint256 => Post) public posts;
    mapping(address => uint256[]) public userPostIds;
    mapping(uint256 => mapping(address => bool)) public hasLiked;

    // Daily post limit per user
    mapping(address => uint256) public lastPostDay;
    mapping(address => uint256) public dailyPostCount;
    uint256 public constant MAX_DAILY_POSTS = 20;

    event PostCreated(uint256 indexed postId, address indexed author, string arweaveId, string contentType, uint256 timestamp);
    event PostLiked(uint256 indexed postId, address indexed liker, uint256 newLikeCount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor(address _pointsSystem) {
        owner = msg.sender;
        pointsSystem = IPointsSystem(_pointsSystem);
    }

    function createPost(string calldata arweaveId, string calldata contentType) external returns (uint256) {
        require(bytes(arweaveId).length > 0, "Arweave ID required");
        require(
            keccak256(bytes(contentType)) == keccak256(bytes("text")) ||
            keccak256(bytes(contentType)) == keccak256(bytes("image")),
            "Invalid content type"
        );

        // Daily post limit
        uint256 today = block.timestamp / 86400;
        if (lastPostDay[msg.sender] != today) {
            lastPostDay[msg.sender] = today;
            dailyPostCount[msg.sender] = 0;
        }
        require(dailyPostCount[msg.sender] < MAX_DAILY_POSTS, "Daily post limit reached");
        dailyPostCount[msg.sender]++;

        uint256 postId = totalPosts++;
        posts[postId] = Post({
            id: postId,
            author: msg.sender,
            arweaveId: arweaveId,
            contentType: contentType,
            createdAt: block.timestamp,
            likes: 0,
            exists: true
        });

        userPostIds[msg.sender].push(postId);

        // Award points for posting
        uint256 points = keccak256(bytes(contentType)) == keccak256(bytes("image")) ? 15 : 10;
        try pointsSystem.awardPoints(msg.sender, points, "post_created") {} catch {}

        emit PostCreated(postId, msg.sender, arweaveId, contentType, block.timestamp);
        return postId;
    }

    function likePost(uint256 postId) external {
        require(posts[postId].exists, "Post not found");
        require(!hasLiked[postId][msg.sender], "Already liked");
        require(posts[postId].author != msg.sender, "Cannot like own post");

        hasLiked[postId][msg.sender] = true;
        posts[postId].likes++;

        // Award points to post author for receiving a like
        try pointsSystem.awardPoints(posts[postId].author, 2, "post_liked") {} catch {}

        emit PostLiked(postId, msg.sender, posts[postId].likes);
    }

    function getPost(uint256 postId) external view returns (Post memory) {
        require(posts[postId].exists, "Post not found");
        return posts[postId];
    }

    function getUserPostIds(address user) external view returns (uint256[] memory) {
        return userPostIds[user];
    }

    // Get paginated posts for feed (most recent first)
    function getRecentPosts(uint256 offset, uint256 limit) external view returns (Post[] memory) {
        uint256 total = totalPosts;
        if (offset >= total) return new Post[](0);

        uint256 end = total - offset;
        uint256 start = end > limit ? end - limit : 0;
        uint256 count = end - start;

        Post[] memory result = new Post[](count);
        for (uint256 i = 0; i < count; i++) {
            result[i] = posts[start + i];
        }
        return result;
    }

    function setPointsSystem(address _pointsSystem) external onlyOwner {
        pointsSystem = IPointsSystem(_pointsSystem);
    }
}

contracts/UserRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract UserRegistry {
    struct User {
        string username;
        string profileArweaveId;  // profile picture stored on Arweave
        uint256 joinedAt;
        bool exists;
    }

    mapping(address => User) public users;
    mapping(string => address) public usernameToAddress;
    address[] public allUsers;

    event UserRegistered(address indexed wallet, string username, uint256 timestamp);
    event ProfileUpdated(address indexed wallet, string profileArweaveId);

    modifier onlyRegistered() {
        require(users[msg.sender].exists, "Not registered");
        _;
    }

    function register(string calldata username) external {
        require(!users[msg.sender].exists, "Already registered");
        require(bytes(username).length >= 3 && bytes(username).length <= 32, "Username 3-32 chars");
        require(usernameToAddress[username] == address(0), "Username taken");

        users[msg.sender] = User({
            username: username,
            profileArweaveId: "",
            joinedAt: block.timestamp,
            exists: true
        });

        usernameToAddress[username] = msg.sender;
        allUsers.push(msg.sender);

        emit UserRegistered(msg.sender, username, block.timestamp);
    }

    function updateProfile(string calldata profileArweaveId) external onlyRegistered {
        users[msg.sender].profileArweaveId = profileArweaveId;
        emit ProfileUpdated(msg.sender, profileArweaveId);
    }

    function getUser(address wallet) external view returns (User memory) {
        return users[wallet];
    }

    function isRegistered(address wallet) external view returns (bool) {
        return users[wallet].exists;
    }

    function getTotalUsers() external view returns (uint256) {
        return allUsers.length;
    }
}

contracts/VaultRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract VaultRegistry {
    struct VaultFile {
        uint256 id;
        address owner;
        string encryptedArweaveId;    // encrypted content on Arweave
        string fileName;               // original file name (not encrypted, just for display)
        string fileType;               // "image", "document", "video", "other"
        string litConditionsHash;      // hash of Lit Protocol access conditions
        uint256 storedAt;
        bool exists;
        bool isDeleted;                // soft delete only — Arweave is permanent
    }

    uint256 public totalFiles;
    mapping(uint256 => VaultFile) private files;
    mapping(address => uint256[]) private userFileIds;

    event FileStored(uint256 indexed fileId, address indexed owner, string fileName, uint256 timestamp);
    event FileDeleted(uint256 indexed fileId, address indexed owner);

    modifier onlyFileOwner(uint256 fileId) {
        require(files[fileId].exists, "File not found");
        require(files[fileId].owner == msg.sender, "Not file owner");
        _;
    }

    function storeFile(
        string calldata encryptedArweaveId,
        string calldata fileName,
        string calldata fileType,
        string calldata litConditionsHash
    ) external returns (uint256) {
        require(bytes(encryptedArweaveId).length > 0, "Arweave ID required");
        require(bytes(fileName).length > 0, "File name required");

        uint256 fileId = totalFiles++;
        files[fileId] = VaultFile({
            id: fileId,
            owner: msg.sender,
            encryptedArweaveId: encryptedArweaveId,
            fileName: fileName,
            fileType: fileType,
            litConditionsHash: litConditionsHash,
            storedAt: block.timestamp,
            exists: true,
            isDeleted: false
        });

        userFileIds[msg.sender].push(fileId);

        emit FileStored(fileId, msg.sender, fileName, block.timestamp);
        return fileId;
    }

    // CRITICAL: Only returns files owned by msg.sender
    function getMyFiles() external view returns (VaultFile[] memory) {
        uint256[] memory ids = userFileIds[msg.sender];
        uint256 count = 0;

        for (uint256 i = 0; i < ids.length; i++) {
            if (!files[ids[i]].isDeleted) count++;
        }

        VaultFile[] memory result = new VaultFile[](count);
        uint256 j = 0;
        for (uint256 i = 0; i < ids.length; i++) {
            if (!files[ids[i]].isDeleted) {
                result[j++] = files[ids[i]];
            }
        }
        return result;
    }

    // Only owner can get file details
    function getFile(uint256 fileId) external view onlyFileOwner(fileId) returns (VaultFile memory) {
        return files[fileId];
    }

    // Soft delete — marks as deleted in registry but Arweave is immutable
    function deleteFile(uint256 fileId) external onlyFileOwner(fileId) {
        files[fileId].isDeleted = true;
        emit FileDeleted(fileId, msg.sender);
    }

    function getMyFileCount() external view returns (uint256) {
        return userFileIds[msg.sender].length;
    }
}

